//import EWGlobalStyles from './EWGlobalStyles';
//import EWPuffs from './EWPuffs';
//import EWButton from './EWButton';
import UAT from './UAT';
import { createRoot } from 'react-dom/client';
import React, { type ReactElement, useState, useEffect } from 'react';
import { Animator } from '@arwes/react-animator';
import { Dots } from '@arwes/react-bgs';

function Sandbox() {

  const [active, setActive] = useState(true);

  useEffect(() => {
    const iid = setInterval(() => setActive(active => !active), 3000);
    return () => clearInterval(iid);
  }, []);

  return (

    <Animator active={active} duration={{ enter: 2, exit: 2 }}>
          <div>
      <div>
      <h1>Entropy Worship</h1>
      <h2>Alpha Build 3.0</h2>  
      <button>test</button>

      <UAT />
    </div>
    </div>
      <div style={{
        position: 'relative',
        width: '80vw',
        height: '80vh'
      }}>
        {/* Canvas element will ocupy the positioned parent element. */}
        <Dots
          color='hsla(180, 100%, 75%, 0.4)'
        />
      </div>
    </Animator>
  );

  }

  createRoot(document.querySelector('#root')).render(<Sandbox />);

  export default Sandbox;
